What does this program print? (Assume `NDEBUG` is NOT defined.)

```cpp
#include <iostream>
#include <cassert>

int clamp(int val, int lo, int hi) {
    assert(lo <= hi);
    if (val < lo) return lo;
    if (val > hi) return hi;
    return val;
}

int main() {
    std::cout << clamp(5, 1, 10) << '\n';
    std::cout << clamp(0, 1, 10) << '\n';
    return 0;
}
```

